import type {SidebarsConfig} from '@docusaurus/plugin-content-docs';

/**
 * Two-audience information architecture, presented Migo-style:
 *  - Products (per tenant) — non-technical operator docs for the configurable end-products.
 *  - SaaS & API — developer docs for building on the 1Platform infrastructure.
 *
 * Each product/API is a top-level **autogenerated** category. Its label, icon
 * and description live in the section's `_category_.json` (the
 * DocSidebarItem/Category swizzle reads `customProps.{icon,description}`, where
 * `icon` is a name from src/components/Icon/icons.ts — colour no longer
 * identifies a product).
 * Each section's `index.mdx` is the category **index page**: per the Docusaurus
 * category-index convention it is auto-linked from the category header (so
 * clicking the product name goes straight to its Overview) and removed from the
 * item list (no duplicate "Overview" entry). The remaining pages are ordered by
 * per-page `sidebar_position` frontmatter. The audience group labels are
 * non-collapsible section headers.
 */
const sidebars: SidebarsConfig = {
  docs: [
    {
      type: 'doc',
      id: 'intro',
      className: 'sidebar-overview',
    },
    {
      type: 'category',
      label: 'Productos (por tenant)',
      collapsible: false,
      collapsed: false,
      className: 'sidebar-section',
      items: [{type: 'autogenerated', dirName: 'products'}],
    },
    {
      type: 'category',
      label: 'SaaS y API',
      collapsible: false,
      collapsed: false,
      className: 'sidebar-section',
      items: [{type: 'autogenerated', dirName: 'saas'}],
    },
  ],
};

export default sidebars;
